import{_ as o,o as c,c as t,au as n}from"./chunks/framework.Bpqx6pAq.js";const m=JSON.parse('{"title":"Offline","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/utilities/utils.offline.md","filePath":"api/core/utilities/utils.offline.md"}'),i={name:"api/core/utilities/utils.offline.md"};function a(r,e,s,l,d,f){return c(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="offline" tabindex="-1">Offline <a class="header-anchor" href="#offline" aria-label="Permalink to &quot;Offline&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <code>utils.offline.js</code> module manages offline-first data synchronisation for KDK applications. It uses an <a href="https://automerge.org/" target="_blank" rel="noreferrer">Automerge</a> CRDT document (via the <code>offline</code> service) and a <code>LocalCache</code> to create, update, and tear down offline-capable service instances.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="async-createofflineservices-offlinedocument" tabindex="-1"><code>async createOfflineServices(offlineDocument?)</code> <a class="header-anchor" href="#async-createofflineservices-offlinedocument" aria-label="Permalink to &quot;`async createOfflineServices(offlineDocument?)`&quot;">​</a></h3><p>Creates offline service instances for all services listed in the <code>LocalCache</code> <code>&#39;services&#39;</code> entry. If <code>offlineDocument</code> is not provided, it is retrieved from cache.</p><ul><li><strong>Parameters:</strong><ul><li><code>offlineDocument</code> <em>(Object, optional)</em>: A pre-fetched offline document. If omitted, fetched from <code>LocalCache</code>.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><h3 id="async-setofflineservicesdocumenthandle-offlinedocument" tabindex="-1"><code>async setOfflineServicesDocumentHandle(offlineDocument?)</code> <a class="header-anchor" href="#async-setofflineservicesdocumenthandle-offlinedocument" aria-label="Permalink to &quot;`async setOfflineServicesDocumentHandle(offlineDocument?)`&quot;">​</a></h3><p>Updates the Automerge document handle on all existing offline services. Called after authentication to provide a user-scoped document handle.</p><ul><li><strong>Parameters:</strong><ul><li><code>offlineDocument</code> <em>(Object, optional)</em>: A pre-fetched offline document.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><h3 id="async-removeofflineservices" tabindex="-1"><code>async removeOfflineServices()</code> <a class="header-anchor" href="#async-removeofflineservices" aria-label="Permalink to &quot;`async removeOfflineServices()`&quot;">​</a></h3><p>Removes all registered offline services.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><h3 id="async-createofflinedocument-query" tabindex="-1"><code>async createOfflineDocument(query)</code> <a class="header-anchor" href="#async-createofflinedocument-query" aria-label="Permalink to &quot;`async createOfflineDocument(query)`&quot;">​</a></h3><p>Creates a new Automerge offline document via the <code>offline</code> service for the given query, caches it in <code>LocalCache</code>, and returns it. Any previously cached document is removed first.</p><ul><li><strong>Parameters:</strong><ul><li><code>query</code> <em>(Object)</em>: The query used to scope the offline document.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Object&gt;</code> — the created offline document.</li></ul><h3 id="async-getofflinedocument" tabindex="-1"><code>async getOfflineDocument()</code> <a class="header-anchor" href="#async-getofflinedocument" aria-label="Permalink to &quot;`async getOfflineDocument()`&quot;">​</a></h3><p>Retrieves the cached offline document and resolves its document handle via the Automerge repository.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;Object | undefined&gt;</code> — the offline document with a <code>documentHandle</code>, or <code>undefined</code> if none is cached.</li></ul><h3 id="async-getofflinedocumentcontent-offlinedocument" tabindex="-1"><code>async getOfflineDocumentContent(offlineDocument?)</code> <a class="header-anchor" href="#async-getofflinedocumentcontent-offlinedocument" aria-label="Permalink to &quot;`async getOfflineDocumentContent(offlineDocument?)`&quot;">​</a></h3><p>Fetches the full content of the offline document, separating metadata (<code>__meta</code>) from actual data.</p><ul><li><strong>Parameters:</strong><ul><li><code>offlineDocument</code> <em>(Object, optional)</em>: A pre-fetched offline document. If omitted, fetched from cache.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Object | undefined&gt;</code> — the offline document enriched with <code>content</code> and <code>metadata</code> properties.</li></ul><h3 id="async-removeofflinedocument" tabindex="-1"><code>async removeOfflineDocument()</code> <a class="header-anchor" href="#async-removeofflinedocument" aria-label="Permalink to &quot;`async removeOfflineDocument()`&quot;">​</a></h3><p>Removes the cached offline document via the <code>offline</code> service and clears it from <code>LocalCache</code>.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;Object | undefined&gt;</code> — the removed document descriptor, or <code>undefined</code> if none existed.</li></ul><h3 id="async-addservicetocache-service-options" tabindex="-1"><code>async addServiceToCache(service, options?)</code> <a class="header-anchor" href="#async-addservicetocache-service-options" aria-label="Permalink to &quot;`async addServiceToCache(service, options?)`&quot;">​</a></h3><p>Adds a service to the <code>&#39;services&#39;</code> entry in <code>LocalCache</code>, merging the given options.</p><ul><li><strong>Parameters:</strong><ul><li><code>service</code> <em>(string)</em>: The service name.</li><li><code>options</code> <em>(Object, optional)</em>: Options stored alongside the service (e.g. <code>features</code>, <code>context</code>).</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Object&gt;</code> — the updated services cache entry.</li></ul><h3 id="async-removeservicefromcache-service" tabindex="-1"><code>async removeServiceFromCache(service)</code> <a class="header-anchor" href="#async-removeservicefromcache-service" aria-label="Permalink to &quot;`async removeServiceFromCache(service)`&quot;">​</a></h3><p>Removes a service from the <code>&#39;services&#39;</code> entry in <code>LocalCache</code>.</p><ul><li><strong>Parameters:</strong><ul><li><code>service</code> <em>(string)</em>: The service name.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Object | undefined&gt;</code> — the removed service options, or <code>undefined</code> if the service was not cached.</li></ul>',31)])])}const h=o(i,[["render",a]]);export{m as __pageData,h as default};
